-- ============================================
-- Legislacao full-site: paulo-martins-gov-pr / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/193726
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = paulo-martins-gov-pr-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 75
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=193726, tipo Deputado(a), ordemAssinatura=1.
-- 25 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'paulo-martins-gov-pr';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'paulo-martins-gov-pr: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao paulo-martins-gov-pr: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2344534', '2330107', '2327145', '2319757', '2319350', '2317941', '2316870', '2316311', '2310637', '2306268', '2305845', '2305609', '2305535', '2303401', '2301809', '2329645', '2326663', '2322412', '2319756', '2319312', '2316622', '2310542', '2308198', '2307450', '2306258', '2305818', '2305608', '2305532', '2303348', '2301787', '2326317', '2319755', '2318835', '2317505', '2316621', '2310161', '2308197', '2307144', '2306250', '2305657', '2305565', '2302465', '2301211', '2327147', '2318400', '2317482', '2316620', '2309780', '2306270', '2305847', '2305650', '2305540', '2304334', '2302464', '2327146', '2319351', '2318399', '2317481', '2316618', '2310638', '2309580', '2307454', '2306269', '2305846', '2305613', '2305538', '2304217', '2302242', '2319610', '2317940', '2332369', '2332179', '2325268', '2307453', '2320125');
  IF target_present <> 75 THEN
    RAISE EXCEPTION 'Pre-condicao paulo-martins-gov-pr: esperadas 75 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2344534', '2330107', '2327145', '2319757', '2319350', '2317941', '2316870', '2316311', '2310637', '2306268', '2305845', '2305609', '2305535', '2303401', '2301809', '2329645', '2326663', '2322412', '2319756', '2319312', '2316622', '2310542', '2308198', '2307450', '2306258', '2305818', '2305608', '2305532', '2303348', '2301787', '2326317', '2319755', '2318835', '2317505', '2316621', '2310161', '2308197', '2307144', '2306250', '2305657', '2305565', '2302465', '2301211', '2327147', '2318400', '2317482', '2316620', '2309780', '2306270', '2305847', '2305650', '2305540', '2304334', '2302464', '2327146', '2319351', '2318399', '2317481', '2316618', '2310638', '2309580', '2307454', '2306269', '2305846', '2305613', '2305538', '2304217', '2302242', '2319610', '2317940', '2332369', '2332179', '2325268', '2307453', '2320125')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'paulo-martins-gov-pr-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao paulo-martins-gov-pr: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao paulo-martins-gov-pr: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

